query:
UPDATE suppliers 
SET description = TRIM(
  REGEXP_REPLACE(
    REGEXP_REPLACE(
      description,
      '<!--\\s*/?wp:[^>]*-->',
      ''
    ),
    '\\n{3,}',
    '\n\n'
  )
)
WHERE description IS NOT NULL 
  AND description LIKE '%<!-- wp:%';
SELECT COUNT(*) as updated_count FROM suppliers WHERE description NOT LIKE '%<!-- wp:%' AND description IS NOT NULL;

